document.querySelector(".header__burger").addEventListener("click",()=>{document.querySelector(".header__burger").classList.toggle("active"),document.querySelector(".navbar-nav").classList.toggle("active"),document.querySelector("body").classList.toggle("burger__active")}),$(document).ready((function(){$(".shop").bind("touchstart mouseover",(function(e){const t=e.pageX/window.innerWidth,r=e.pageY/window.innerHeight;document.querySelector(".hearts").style.transform="translate("+15*t+"px, "+15*r+"px)",document.querySelector(".inst").style.transform="translate(-"+40*t+"px, -"+20*r+"px)",document.querySelector(".hearts_bot").style.transform="translate("+30*t+"px, "+20*r+"px) rotate(20deg)",document.querySelector(".inst_bot").style.transform="translate(-"+25*t+"px, -"+25*r+"px)"})),$(".news").bind("touchstart mouseover",(function(e){const t=e.pageX/window.innerWidth,r=e.pageY/window.innerHeight;document.querySelector(".news__teleg-top").style.transform="translate(-"+40*t+"px, -"+10*r+"px)",document.querySelector(".news__teleg-bot").style.transform="translate("+25*t+"px, "+15*r+"px) rotate(-20deg)"})),$(".nav-link").click((function(e){document.querySelector(".header__burger").classList.remove("active"),document.querySelector(".navbar-nav").classList.remove("active"),document.querySelector("body").classList.remove("burger__active")}));let e=window.pageYOffset;$(window).scroll((function(){window.pageYOffset>100?document.querySelector(".header").classList.add("sect1"):document.querySelector(".header").classList.remove("sect1")})),e>100?document.querySelector(".header").classList.add("sect1"):document.querySelector(".header").classList.remove("sect1")}));